import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Allocate a dynamic buffer with size based on user input length
        byte[] buffer = new byte[input.length()];

        // Copying user input into the buffer with proper bounds checking
        System.arraycopy(input.getBytes(), 0, buffer, 0, Math.min(input.length(), buffer.length));

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
